// === BUILD PROMPT v4.0 — Enrichment LLM Venta ===
// Lee descripcion de datos_json_enrichment (ya guardada por enrichment regex)
// NO necesita Firecrawl — todo el contenido ya está en BD

const prop = $('Loop Propiedades').first().json;
const allPm = $('Cargar Proyectos Master').all().map(i => i.json);

const enrichment = typeof prop.datos_json_enrichment === 'string'
  ? JSON.parse(prop.datos_json_enrichment)
  : (prop.datos_json_enrichment || {});

const descripcion = (enrichment.descripcion || '').substring(0, 3000);

if (!descripcion || descripcion.length < 30) {
  return [{ json: { skip: true, error: 'Sin descripcion suficiente', prop_id: prop.prop_id } }];
}

// Filter PM by zona
const pmZona = allPm.filter(p => p.zona === prop.zona);
const pmList = pmZona.map(p => `- ${p.nombre_oficial} (ID ${p.id_proyecto_master})`).join('\n') || '(sin proyectos cargados)';

// Extract titulo and ubicacion if available in enrichment data
const titulo = enrichment.titulo_anuncio || enrichment.titulo || '';
const ubicacion = enrichment.ubicacion_detalle || enrichment.ubicacion || '';

// Nombre edificio — limpiar basura
const BASURA = ['venta', 'pre venta', 'preventa', 'departamento', 'en venta', ''];
const nombreRaw = prop.nombre_edificio || '';
const nombre = BASURA.includes(nombreRaw.toLowerCase().trim()) ? 'no detectado' : nombreRaw;

const prompt = `Eres un extractor de datos inmobiliarios para Santa Cruz de la Sierra, Bolivia.
Extraes datos de páginas web de propiedades en VENTA.
REGLA ABSOLUTA: NUNCA inventes datos. Si no aparece en el texto, devuelve null.

═══════════════════════════════════════
TÍTULO DEL ANUNCIO:
${titulo || '(no disponible)'}

UBICACIÓN:
${ubicacion || '(no disponible)'}

DATOS PORTAL (metadata estructurada del portal — confiables):
- URL: ${prop.url || 'desconocida'}
- Fuente: ${prop.fuente || 'desconocida'}
- Precio: $${prop.precio_usd || '?'} USD (moneda original: ${prop.moneda_original || 'desconocida'})
- Área: ${prop.area_total_m2 ? prop.area_total_m2 + ' m²' : 'desconocida'}
- Dormitorios (portal): ${prop.dormitorios ?? 'desconocido'}
- Baños (portal): ${prop.banos ?? 'desconocido'}

DATOS EXTRACTOR (regex — pueden tener errores):
- Nombre edificio: ${nombre}
- Estado construcción: ${prop.estado_construccion || 'no detectado'}
- Tipo cambio: ${prop.tipo_cambio_detectado || 'no detectado'}
- Zona GPS: ${prop.zona || 'desconocida'}

PROYECTOS CONOCIDOS EN ZONA ${prop.zona || '?'}:
${pmList}

DESCRIPCIÓN:
${descripcion}
═══════════════════════════════════════

INSTRUCCIONES POR CAMPO:
═══════════════════════════════════════

PRIORIDAD: Si título/ubicación/descripción CONTRADICE un dato portal o extractor, usar la evidencia del texto. Si no hay contradicción, mantener el dato existente.

NOMBRE_EDIFICIO:
- Buscá el nombre del edificio/condominio/proyecto en título, ubicación y descripción
- Compará contra la lista de PROYECTOS CONOCIDOS de arriba
- Si encontrás match (incluso parcial: "Edif Nomad" → "Nomad by Smart Studio"), usá el nombre oficial de la lista
- Si no hay match pero el texto tiene un nombre claro, devolvelo tal cual
- Si no hay nombre en el texto, devolvé null
- NUNCA devolver: "Venta", "Pre Venta", "Departamento", fragmentos de oraciones

DORMITORIOS:
- Buscar en título/descripción: "monoambiente", "studio", "loft" = 0 dormitorios
- "1 dormitorio", "1 dorm", "1 hab" = 1
- Si el portal dice 1 pero el texto dice "monoambiente" o "studio" → usar 0
- Si el portal dice un número y el texto no lo contradice → mantener el del portal
- Rango válido: 0-6

BAÑOS:
- Buscar en título/descripción cantidad de baños
- "medio baño" o "toilette" cuenta como 0.5
- Si el portal dice un número y el texto no lo contradice → mantener el del portal
- Rango válido: 0-6

ESTADO_CONSTRUCCION:
- Solo 2 valores válidos:
  - "preventa": "precios desde", "entrega [fecha futura]", "en construcción", "obra gruesa", "avance X%", fecha de entrega futura
  - "entrega_inmediata": "listo para vivir", "entrega inmediata", "listo para ocupar", "a estrenar", inmueble terminado
- Si no hay evidencia clara → null
- CUIDADO: "amoblado" o "equipado" SOLOS no implican entrega_inmediata

TIPO_CAMBIO_DETECTADO:
- "paralelo": "TC paralelo", "al paralelo", "dólares o paralelo", "solo dólares", "tc del día", "pago en dólares", "blue", "dólar blue", "al blue", "USDT", "cripto"
- "oficial": "TC 7", "al cambio Bs.7", "TC oficial", "tipo de cambio 7", precio listado SOLO en Bs/bolivianos sin mención de USD
- "no_especificado": si no hay mención de TC ni forma de pago. NUNCA devolver null — usar "no_especificado"

PARQUEO_INCLUIDO:
- true: "incluye parqueo", "con parqueo" sin precio aparte
- false: "Parqueo: $us X" (precio explícito) O no se menciona parqueo en absoluto
- DEFAULT: false

BAULERA_INCLUIDA:
- true: "incluye baulera", "con baulera" sin precio aparte
- false: si no se menciona baulera, o precio explícito por baulera
- DEFAULT: false

ES_MULTIPROYECTO:
- true: el anuncio NO tiene precio + área + dormitorios definidos en DATOS PORTAL simultáneamente, Y la descripción habla del proyecto en general sin identificar una unidad específica
- false: si DATOS PORTAL tiene precio, área Y dormitorios definidos → siempre false
- DEFAULT: false
- CLAVE: solo marcar true cuando faltan 2 o más de estos 3 datos en metadata: precio, área, dormitorios

PLAN_PAGOS:
- tiene_plan_pagos: true si cuotas/financiamiento, false si solo contado o no hay info. DEFAULT: false
- plan_pagos_texto: resumen breve de condiciones, null si no hay info
- descuento_contado_pct: porcentaje de descuento por pago contado, null si no se menciona
- acepta_permuta: true si menciona permuta/canje, false si no. DEFAULT: false
- precio_negociable: true si "negociable"/"escucha ofertas", false si no. DEFAULT: false
- solo_tc_paralelo: true si la descripción menciona dólares o TC paralelo como forma de pago, en cualquier combinación. DEFAULT: false\n- true: "pago en dólares", "solo dólares", "TC paralelo", "dólares o paralelo", "dólares y/o paralelo"\n- false: solo si acepta explícitamente bolivianos o TC oficial. Ej: "dólares o bolivianos", "se acepta Bs", "al cambio oficial"\n- CLAVE: cualquier mención de dólares/paralelo SIN mención de bolivianos/oficial = true\n- CLAVE: si no hay info de forma de pago = false (default)

AMENITIES y EQUIPAMIENTO:
- Solo lo que el texto CONFIRME explícitamente
- NUNCA inferir sin mención explícita

═══════════════════════════════════════

Devuelve SOLO este JSON (sin explicaciones, sin markdown):
{
  "nombre_edificio": string | null,
  "nombre_edificio_confianza": "alta" | "media" | "baja" | null,
  "dormitorios": number | null,
  "dormitorios_confianza": "alta" | "media" | "baja" | null,
  "banos": number | null,
  "estado_construccion": "entrega_inmediata" | "preventa" | null,
  "estado_construccion_confianza": "alta" | "media" | "baja" | null,
  "fecha_entrega_estimada": string | null,
  "es_multiproyecto": boolean | null,
  "tipo_cambio_detectado": "paralelo" | "oficial" | "no_especificado",
  "tipo_cambio_confianza": "alta" | "media" | "baja" | null,
  "piso": number | null,
  "parqueo_incluido": boolean | null,
  "parqueo_precio_adicional_usd": number | null,
  "baulera_incluida": boolean | null,
  "baulera_precio_adicional_usd": number | null,
  "plan_pagos": {
    "tiene_plan_pagos": boolean | null,
    "plan_pagos_texto": string | null,
    "descuento_contado_pct": number | null,
    "acepta_permuta": boolean | null,
    "precio_negociable": boolean | null,
    "solo_tc_paralelo": boolean | null
  },
  "descripcion_limpia": string,
  "amenities_confirmados": string[],
  "equipamiento_detectado": string[]
}`;

return [{
  json: {
    prop_id: prop.prop_id,
    prop_url: prop.url,
    fuente: prop.fuente,
    prompt: prompt,
    contenido_length: descripcion.length
  }
}];

// === PARSE & VALIDATE v4.0 — Enrichment LLM Venta ===
const prop_id = $('Build Prompt v4.0').first().json.prop_id;
const prop_url = $('Build Prompt v4.0').first().json.prop_url;
const response = $input.first().json;

const text = response?.content?.[0]?.text || '';
const inputTokens = response?.usage?.input_tokens || 0;
const outputTokens = response?.usage?.output_tokens || 0;
const tokens = inputTokens + outputTokens;

// Extract JSON
let jsonStr = text;
const jsonMatch = text.match(/```(?:json)?\s*([\s\S]*?)```/);
if (jsonMatch) {
  jsonStr = jsonMatch[1].trim();
} else {
  const braceMatch = text.match(/\{[\s\S]*\}/);
  if (braceMatch) jsonStr = braceMatch[0];
}

let datos_llm;
let errores = [];
let requiere_revision = false;

try {
  datos_llm = JSON.parse(jsonStr);
} catch (e) {
  errores.push('json_parse_error: ' + e.message);
  requiere_revision = true;
  datos_llm = null;
}

// Si parse falló, skip validaciones — enviar solo metadata
if (!datos_llm) {
  return [{
    json: {
      prop_id: prop_id,
      prop_url: prop_url,
      datos_llm: null,
      tokens_usados: tokens,
      errores: errores,
      requiere_revision: true,
      parse_error: true
    }
  }];
}

// === VALIDACIONES ===
const VALID_ESTADOS = ['entrega_inmediata', 'preventa'];
const VALID_TC = ['paralelo', 'oficial', 'no_especificado'];
const VALID_CONFIANZA = ['alta', 'media', 'baja'];

// estado_construccion: solo 2 valores
if (datos_llm.estado_construccion && !VALID_ESTADOS.includes(datos_llm.estado_construccion)) {
  errores.push('estado_construccion_invalido: ' + datos_llm.estado_construccion);
  datos_llm.estado_construccion = null;
}

// tipo_cambio_detectado
if (datos_llm.tipo_cambio_detectado && !VALID_TC.includes(datos_llm.tipo_cambio_detectado)) {
  errores.push('tipo_cambio_invalido: ' + datos_llm.tipo_cambio_detectado);
  datos_llm.tipo_cambio_detectado = 'no_especificado';
}

// confianza fields
for (const field of ['nombre_edificio_confianza', 'estado_construccion_confianza', 'tipo_cambio_confianza', 'dormitorios_confianza']) {
  if (datos_llm[field] && !VALID_CONFIANZA.includes(datos_llm[field])) {
    datos_llm[field] = null;
  }
}

// dormitorios: 0-6
if (datos_llm.dormitorios !== null && datos_llm.dormitorios !== undefined) {
  if (datos_llm.dormitorios < 0 || datos_llm.dormitorios > 6) {
    errores.push('dormitorios_fuera_rango: ' + datos_llm.dormitorios);
    datos_llm.dormitorios = null;
  }
}

// banos: 0-6
if (datos_llm.banos !== null && datos_llm.banos !== undefined) {
  if (datos_llm.banos < 0 || datos_llm.banos > 6) {
    errores.push('banos_fuera_rango: ' + datos_llm.banos);
    datos_llm.banos = null;
  }
}

// piso: -2 to 40
if (datos_llm.piso !== null && datos_llm.piso !== undefined) {
  if (datos_llm.piso < -2 || datos_llm.piso > 40) {
    errores.push('piso_fuera_rango: ' + datos_llm.piso);
    datos_llm.piso = null;
  }
}

// parqueo_precio_adicional_usd: 0-50000
if (datos_llm.parqueo_precio_adicional_usd !== null && datos_llm.parqueo_precio_adicional_usd !== undefined) {
  if (datos_llm.parqueo_precio_adicional_usd < 0 || datos_llm.parqueo_precio_adicional_usd > 50000) {
    errores.push('parqueo_precio_fuera_rango: ' + datos_llm.parqueo_precio_adicional_usd);
    datos_llm.parqueo_precio_adicional_usd = null;
  }
}

// baulera_precio_adicional_usd: 0-20000
if (datos_llm.baulera_precio_adicional_usd !== null && datos_llm.baulera_precio_adicional_usd !== undefined) {
  if (datos_llm.baulera_precio_adicional_usd < 0 || datos_llm.baulera_precio_adicional_usd > 20000) {
    errores.push('baulera_precio_fuera_rango: ' + datos_llm.baulera_precio_adicional_usd);
    datos_llm.baulera_precio_adicional_usd = null;
  }
}

// descuento_contado_pct: 0-30
if (datos_llm.plan_pagos?.descuento_contado_pct !== null && datos_llm.plan_pagos?.descuento_contado_pct !== undefined) {
  if (datos_llm.plan_pagos.descuento_contado_pct < 0 || datos_llm.plan_pagos.descuento_contado_pct > 30) {
    errores.push('descuento_fuera_rango: ' + datos_llm.plan_pagos.descuento_contado_pct);
    datos_llm.plan_pagos.descuento_contado_pct = null;
  }
}

// Ensure arrays
if (!Array.isArray(datos_llm.amenities_confirmados)) datos_llm.amenities_confirmados = [];
if (!Array.isArray(datos_llm.equipamiento_detectado)) datos_llm.equipamiento_detectado = [];

if (errores.length > 2) requiere_revision = true;

return [{
  json: {
    prop_id: prop_id,
    prop_url: prop_url,
    datos_llm: datos_llm,
    tokens_usados: tokens,
    errores: errores,
    requiere_revision: requiere_revision
  }
}];

// === RESUMEN ENRICHMENT LLM VENTA ===
const lote = $('Query Ventas Pendientes').all();
const totalLote = lote.filter(i => i.json.prop_id).length;

return [{ json: {
  timestamp: new Date().toISOString(),
  workflow: 'Enrichment LLM Venta',
  version: '1.0.0',
  prompt_version: 'v4.0',
  modelo: 'claude-haiku-4-5-20251001',
  modo: 'observacion',
  total_lote: totalLote,
  status: 'completado'
}}];

// === SKIP: prompt no construido ===
const prop_id = $('Build Prompt v4.0').first().json.prop_id;
console.log('WARN: Prompt skip para prop ' + prop_id);
return [{ json: { skip: true, prop_id: prop_id, error: 'prompt_skip' } }];
